module top_module(
    input CLK,
    input EN,
    input TE,
    output ENCLK
);wire n2;
    reg obf_EN_reg;

    always @ (posedge CLK, posedge TE) begin
        if (TE) begin
            obf_EN_reg <= 1'b0;
        end else begin
            obf_EN_reg <= EN;
        end
    end

    assign n2 = obf_EN_reg & CLK;
    assign ENCLK = n2;

endmodule
